// Created: 2026-02-18

/**
 * Normalize shell commands for safe pattern matching.
 * Prevents bypass via quoting, escapes, and compound operators.
 *
 * Issue #687: centralizes normalization that was previously ad-hoc
 * across dangerous-command-blocker, auto-approve-safe-bash, and learning-tracker.
 */

/**
 * Expand hex escapes: \x72\x6d -> rm
 */
function expandHexEscapes(cmd: string): string {
  return cmd.replace(/\\x([0-9a-fA-F]{2})/g, (_match, hex) =>
    String.fromCharCode(parseInt(hex, 16))
  );
}

/**
 * Expand octal escapes: \162\155 -> rm
 */
function expandOctalEscapes(cmd: string): string {
  return cmd.replace(/\\([0-7]{3})/g, (_match, oct) =>
    String.fromCharCode(parseInt(oct, 8))
  );
}

/**
 * Strip backslash escapes from individual characters: r\m -> rm, r\\m -> rm
 * Runs AFTER hex/octal expansion so those are already resolved.
 */
function stripBackslashEscapes(cmd: string): string {
  // Remove backslash before any non-whitespace character (escape bypass)
  return cmd.replace(/\\([^\s])/g, '$1');
}

/**
 * Strip wrapping quotes from tokens: "rm" -> rm, 'rm' -> rm
 * Handles full-token quoting and inline quoting like r"m" -> rm
 */
function stripQuotes(cmd: string): string {
  // Remove matched single or double quotes around content
  let result = cmd;
  // Strip double-quoted segments: "..." -> content
  result = result.replace(/"([^"]*)"/g, '$1');
  // Strip single-quoted segments: '...' -> content
  result = result.replace(/'([^']*)'/g, '$1');
  return result;
}

/**
 * Normalize a single sub-command (no splitting, just cleaning).
 * - Expand hex/octal escapes
 * - Strip backslash escapes
 * - Strip quotes
 * - Remove line continuations
 * - Collapse whitespace
 */
export function normalizeSingle(cmd: string): string {
  let result = cmd;
  result = expandHexEscapes(result);
  result = expandOctalEscapes(result);
  result = stripBackslashEscapes(result);
  result = stripQuotes(result);
  // Remove line continuations (backslash + newline)
  result = result.replace(/\\\s*[\r\n]+/g, ' ');
  // Replace remaining newlines
  result = result.replace(/\n/g, ' ');
  // Collapse whitespace
  result = result.replace(/\s+/g, ' ');
  return result.trim();
}

/**
 * Normalize a shell command for safe matching.
 * Strips quoting, expands escapes, splits compound operators.
 * Returns array of individual normalized sub-commands.
 */
export function normalizeCommand(cmd: string): string[] {
  if (!cmd?.trim()) return [];

  // Pre-process: expand escapes and strip quotes on the raw input,
  // but preserve newlines and compound operators for splitting.
  let preprocessed = cmd;
  preprocessed = expandHexEscapes(preprocessed);
  preprocessed = expandOctalEscapes(preprocessed);
  preprocessed = stripBackslashEscapes(preprocessed);
  preprocessed = stripQuotes(preprocessed);
  // Remove line continuations (backslash + newline) — these join lines
  preprocessed = preprocessed.replace(/\\\s*[\r\n]+/g, ' ');

  // Split on compound operators (&&, ||, |, ;) AND newlines
  const parts = preprocessed.split(/\s*(?:&&|\|\||\||;|\n)\s*/);

  // Normalize whitespace in each part and filter empties
  return parts
    .map((p) => p.replace(/\s+/g, ' ').trim())
    .filter(Boolean);
}

/**
 * Check if any sub-command in a compound command matches a dangerous pattern.
 * Patterns are matched as lowercase substrings against each normalized sub-command.
 */
export function containsDangerousCommand(
  cmd: string,
  patterns: string[]
): { matches: boolean; matched?: string; subCommand?: string } {
  const subCommands = normalizeCommand(cmd);

  for (const sub of subCommands) {
    const lowerSub = sub.toLowerCase();
    for (const pattern of patterns) {
      if (lowerSub.includes(pattern.toLowerCase())) {
        return { matches: true, matched: pattern, subCommand: sub };
      }
    }
  }

  return { matches: false };
}

/**
 * Blank out content inside single- and double-quoted strings.
 * Bash does NOT perform brace expansion, process substitution, etc. inside
 * quotes, so detection must ignore quoted regions to avoid false positives.
 * Example: --jq '{title, labels}' → --jq '___'
 *
 * Exported for callers that need SHELL-FAITHFUL parsing rather than the
 * bypass-resistant parsing normalizeCommand() provides (#2947). Quoted
 * regions are opaque payload to the shell: operators inside them are NOT
 * stage separators.
 */
export function blankQuotedContent(cmd: string): string {
  // Single-quoted strings: no escaping possible inside single quotes in bash
  let result = cmd.replace(/'[^']*'/g, "''");
  // Double-quoted strings: handle escaped quotes inside
  result = result.replace(/"(?:[^"\\]|\\.)*"/g, '""');
  return result;
}

/**
 * Blank the BODY of quoted heredocs (`<<'EOF'` / `<<"EOF"`, and the `<<-`
 * tab-stripping forms).
 *
 * A quoted heredoc delimiter disables ALL expansion in bash: the body is inert
 * payload, exactly like a single-quoted string. Scanning it for shell features
 * is a false positive — `cat > s.sh <<'EOF'` writing a script that merely
 * CONTAINS `<(...)`, `<<<`, or `IFS=` was being blocked even though bash never
 * interprets those bytes.
 *
 * UNQUOTED heredocs (`<<EOF`) still perform parameter and command substitution,
 * so their bodies are deliberately left intact for scanning.
 */
export function blankQuotedHeredocBodies(cmd: string): string {
  // <<['"]DELIM['"] ... newline DELIM  — non-greedy body, delimiter on its own line.
  // Bounded quantifiers avoid ReDoS on untrusted input (CodeQL SEC-003).
  return cmd.replace(
    /(<<-?\s*(['"])([A-Za-z_][A-Za-z0-9_]{0,63})\2)([\s\S]{0,20000}?)(^[ \t]*\3[ \t]*$)/gm,
    (_m, open: string, _q: string, _delim: string, _body: string, close: string) =>
      `${open}\n${close}`,
  );
}

/**
 * Detect suspicious shell features that bypass simple operator splitting.
 * Returns array of finding descriptions, empty if clean.
 *
 * Detects: process substitution, brace expansion (command form), here-strings,
 * IFS manipulation, and nested command substitution.
 */
export function detectSuspiciousShellFeatures(cmd: string): string[] {
  const findings: string[] = [];

  // Strip inert payload before scanning: quoted-heredoc bodies first (they may
  // themselves contain quotes), then quoted strings. Bash expands neither.
  const unquoted = blankQuotedContent(blankQuotedHeredocBodies(cmd));

  // 1. Process substitution: <(cmd) or >(cmd)
  // Limit content length to avoid ReDoS on untrusted input (CodeQL SEC-003)
  if (/[<>]\([^)]{1,500}\)/.test(unquoted)) {
    findings.push('process substitution detected (<(...) or >(...))');
  }

  // 2. Brace expansion (command form): {cat,/etc/passwd}
  // Heuristic: flag when the first element looks like a command binary (3+ chars,
  // no dots/slashes, starts alpha). Short elements like {ts,js} are file extensions.
  // Limit quantifiers to avoid ReDoS on untrusted input (CodeQL SEC-003)
  const braceMatch = unquoted.match(/\{([^},]{1,200}),([^}]{1,500})\}/g);
  if (braceMatch) {
    for (const m of braceMatch) {
      const inner = m.slice(1, -1);
      const firstElement = inner.split(',')[0].trim();
      // Skip file extension globs (1-2 char tokens like {ts,js}) and paths with dots/slashes
      const isLikelyExtension = firstElement.length <= 2;
      const hasPathChars = firstElement.includes('.') || firstElement.includes('/');
      // Also check if preceded by a dot or glob (*.{ts,js}) — definitely a file glob
      const braceIdx = unquoted.indexOf(m);
      const charBefore = braceIdx > 0 ? unquoted[braceIdx - 1] : '';
      const isPrecededByGlob = charBefore === '.' || charBefore === '*' || charBefore === '/';
      // Bash brace expansion requires NO spaces between elements: {cat,/etc/passwd}
      // Spaced patterns like {name, os, status} are NOT valid brace expansion —
      // bash treats the space as a word separator. Also skip JSON/jq object syntax
      // (contains ':') since it's never brace expansion.
      const hasSpacedElements = inner.includes(', ');
      const hasJsonSyntax = inner.includes(':');
      if (firstElement && !isLikelyExtension && !hasPathChars && !isPrecededByGlob && !hasSpacedElements && !hasJsonSyntax && /^[a-zA-Z]/.test(firstElement)) {
        findings.push(`brace expansion with command-like pattern: ${m}`);
      }
    }
  }

  // 3. Here-strings feeding a shell interpreter: `bash <<< "$code"`
  //
  // A here-string is a redirection, not a stage separator, so `<<<` on its own
  // bypasses nothing. Blocking it categorically rejected ordinary commands
  // (`grep x <<< "$v"`, `jq . <<< "$json"`, `wc -l <<< "$out"`) while the
  // sibling redirections `<` and `<<` stayed allowed — inconsistent, and it
  // fired constantly in real sessions.
  //
  // The risk is the RECEIVER, exactly as with `| bash`: feeding a string to an
  // interpreter executes it. So flag only when the stage containing `<<<`
  // starts with one.
  for (const stage of unquoted.split(/(?:&&|\|\||[;|\n])/)) {
    const idx = stage.indexOf('<<<');
    if (idx < 0) continue;
    const head = stage.slice(0, idx).trim();
    const firstWord = head.split(/\s+/)[0] ?? '';
    if (/^(sh|bash|zsh|dash|python[23]?|node|perl|ruby|tclsh)$/i.test(firstWord)) {
      findings.push('here-string feeding a shell interpreter detected');
      break;
    }
  }

  // 4. IFS manipulation: ${IFS} or IFS= assignment
  if (/\$\{?IFS\}?/.test(unquoted) || /\bIFS=/.test(unquoted)) {
    findings.push('IFS manipulation detected');
  }

  // 5. Nested command substitution: $(echo `cmd`) or $(`cmd`)
  // Use indexOf-based detection to avoid ReDoS (CodeQL SEC-003)
  const dpIdx = unquoted.indexOf('$(');
  if (dpIdx >= 0) {
    const cpIdx = unquoted.indexOf(')', dpIdx + 2);
    if (cpIdx > dpIdx) {
      const inner = unquoted.substring(dpIdx + 2, cpIdx);
      if (inner.includes('`')) {
        findings.push('nested command substitution detected ($(..`..`..))');
      }
    }
  }

  return findings;
}

/**
 * Check if a command is a compound command (contains operators like &&, ||, ;, |, or newlines).
 */
export function isCompoundCommand(cmd: string): boolean {
  // Check for newlines BEFORE normalization (normalization converts \n to space)
  // But ignore line continuations (backslash + newline) which join lines
  const withoutContinuations = cmd.replace(/\\\s*[\r\n]+/g, ' ');
  if (/\n/.test(withoutContinuations)) return true;

  // Check the normalized form for compound operators
  const normalized = normalizeSingle(cmd);
  return /(?:&&|\|\||[|;])/.test(normalized);
}
